import{_ as a,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Приложение: Справочник по конфигурации и миграции | oh-my-opencode","description":"Изучите справочник по конфигурации oh-my-opencode, руководство по совместимости с Claude Code и использование встроенных MCP-серверов. Узнайте о параметрах конфигурации, шагах миграции и настройке возможностей поиска для бесшовной миграции из Claude Code.","frontmatter":{"title":"Приложение: Справочник по конфигурации и миграции | oh-my-opencode","sidebarTitle":"Справочник и миграция","subtitle":"Приложение: Справочник по конфигурации и миграции","description":"Изучите справочник по конфигурации oh-my-opencode, руководство по совместимости с Claude Code и использование встроенных MCP-серверов. Узнайте о параметрах конфигурации, шагах миграции и настройке возможностей поиска для бесшовной миграции из Claude Code.","tags":["Приложение","Справочник"],"order":170},"headers":[],"relativePath":"ru/code-yeongyu/oh-my-opencode/appendix/index.md","filePath":"ru/code-yeongyu/oh-my-opencode/appendix/index.md"}'),d={name:"ru/code-yeongyu/oh-my-opencode/appendix/index.md"};function i(l,e,n,s,h,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="приложение-справочник-по-конфигурации-и-миграции" tabindex="-1">Приложение: Справочник по конфигурации и миграции <a class="header-anchor" href="#приложение-справочник-по-конфигурации-и-миграции" aria-label="Permalink to &quot;Приложение: Справочник по конфигурации и миграции&quot;">​</a></h1><p>Эта глава содержит подробные справочные материалы и рекомендации по совместимости для <strong>oh-my-opencode</strong>, включая полную документацию по конфигурации, поддержку миграции из Claude Code и детальное описание встроенных серверов расширений.</p><h2 id="содержание-главы" tabindex="-1">Содержание главы <a class="header-anchor" href="#содержание-главы" aria-label="Permalink to &quot;Содержание главы&quot;">​</a></h2><p>Эта глава включает три важных раздела:</p><table tabindex="0"><thead><tr><th>Подстраница</th><th>Описание</th><th>Сложность</th></tr></thead><tbody><tr><td><a href="./claude-code-compatibility/">Совместимость с Claude Code</a></td><td>Полное руководство по миграции из Claude Code в OpenCode, включая механизмы совместимости для Commands, Skills, Agents, MCPs и Hooks</td><td>⭐⭐</td></tr><tr><td><a href="./configuration-reference/">Справочник по конфигурации</a></td><td>Полная документация Schema для файлов конфигурации oh-my-opencode, охватывающая все поля, типы и значения по умолчанию</td><td>⭐⭐⭐</td></tr><tr><td><a href="./builtin-mcps/">Встроенные MCP</a></td><td>Функциональность и использование 3 встроенных MCP-серверов (Exa Websearch, Context7, Grep.app)</td><td>⭐⭐</td></tr></tbody></table><h2 id="рекомендуемые-пути-обучения" tabindex="-1">Рекомендуемые пути обучения <a class="header-anchor" href="#рекомендуемые-пути-обучения" aria-label="Permalink to &quot;Рекомендуемые пути обучения&quot;">​</a></h2><p>Выберите порядок обучения в соответствии с вашими потребностями:</p><h3 id="путь-1-миграция-из-claude-code" tabindex="-1">Путь 1: Миграция из Claude Code <a class="header-anchor" href="#путь-1-миграция-из-claude-code" aria-label="Permalink to &quot;Путь 1: Миграция из Claude Code&quot;">​</a></h3><p>Если вы пользователь, мигрирующий из Claude Code:</p><ol><li>Сначала прочитайте <strong><a href="./claude-code-compatibility/">Совместимость с Claude Code</a></strong>, чтобы понять, как бесшовно мигрировать существующую конфигурацию</li><li>Затем изучите <strong><a href="./configuration-reference/">Справочник по конфигурации</a></strong>, чтобы глубже понять доступные параметры конфигурации</li><li>Наконец, изучите <strong><a href="./builtin-mcps/">Встроенные MCP</a></strong>, чтобы понять, как настроить дополнительные возможности поиска</li></ol><h3 id="путь-2-глубокая-настроика" tabindex="-1">Путь 2: Глубокая настройка <a class="header-anchor" href="#путь-2-глубокая-настроика" aria-label="Permalink to &quot;Путь 2: Глубокая настройка&quot;">​</a></h3><p>Если вы хотите глубоко настроить поведение oh-my-opencode:</p><ol><li>Начните с <strong><a href="./configuration-reference/">Справочника по конфигурации</a></strong>, чтобы понять все настраиваемые элементы</li><li>Изучите <strong><a href="./builtin-mcps/">Встроенные MCP</a></strong>, чтобы настроить возможности поиска и запросов документации</li><li>Обратитесь к <strong><a href="./claude-code-compatibility/">Совместимости с Claude Code</a></strong>, чтобы понять параметры конфигурации слоя совместимости</li></ol><h3 id="путь-3-быстрыи-справочник" tabindex="-1">Путь 3: Быстрый справочник <a class="header-anchor" href="#путь-3-быстрыи-справочник" aria-label="Permalink to &quot;Путь 3: Быстрый справочник&quot;">​</a></h3><p>Если вам нужно только найти конкретную информацию:</p><ul><li><strong>Вопросы по конфигурации</strong> → Перейдите сразу к <strong><a href="./configuration-reference/">Справочнику по конфигурации</a></strong></li><li><strong>Вопросы по миграции</strong> → Перейдите сразу к <strong><a href="./claude-code-compatibility/">Совместимости с Claude Code</a></strong></li><li><strong>Конфигурация MCP</strong> → Перейдите сразу к <strong><a href="./builtin-mcps/">Встроенным MCP</a></strong></li></ul><h2 id="предварительные-требования" tabindex="-1">Предварительные требования <a class="header-anchor" href="#предварительные-требования" aria-label="Permalink to &quot;Предварительные требования&quot;">​</a></h2><p>Для этой главы рекомендуется, чтобы вы уже:</p><ul><li>✅ Завершили <strong><a href="./../start/installation/">Установку и конфигурацию</a></strong></li><li>✅ Поняли основные концепции <strong><a href="./../start/sisyphus-orchestrator/">Оркестратора Sisyphus</a></strong></li><li>✅ Были знакомы с редактированием файлов конфигурации JSON</li></ul><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этой главы вы можете:</p><ul><li>🚀 Попробовать <strong><a href="./../advanced/">Расширенные функции</a></strong>, чтобы узнать больше о продвинутом использовании</li><li>🔧 Проверить <strong><a href="./../faq/">FAQ</a></strong>, чтобы решить проблемы использования</li><li>📖 Прочитать <strong><a href="./../changelog/">Журнал изменений</a></strong>, чтобы быть в курсе улучшений новых функций</li></ul><div class="tip custom-block"><p class="custom-block-title">Совет</p><p>Содержание этой главы в основном служит справочным материалом и не обязательно для последовательного чтения. Вы можете обращаться к соответствующим разделам по мере необходимости.</p></div>',23)])])}const g=a(d,[["render",i]]);export{p as __pageData,g as default};
